    <script type="application/ld+json">
    {
        "@context": "https://schema.org",
        "@type": "DefinedTermSet",
        "name": "Ecommerce Business Key Terms",
        "definedTerm": [
            {
                "@type": "DefinedTerm",
                "name": "E-Commerce Operator (ECO)",
                "description": "Per Section 2(45) CGST Act - any person who owns, operates or manages a digital or electronic facility or platform for electronic commerce; mandatorily registered under Section 24(x) regardless of turnover; collects TCS under Section 52."
            },
            {
                "@type": "DefinedTerm",
                "name": "Section 24(x) CGST Act",
                "description": "Mandatory GST registration for every E-Commerce Operator regardless of aggregate turnover; requires registration in each State or UT of operations (or Head Office declared as place of business if no physical presence)."
            },
            {
                "@type": "DefinedTerm",
                "name": "Section 24(ix) CGST Act",
                "description": "Mandatory GST registration for persons supplying through an ECO collecting TCS under Section 52; subject to relaxations under Notification 34/2023 (goods sellers threshold INR 40 lakh) and Notification 65/2017 (services threshold INR 20 lakh)."
            },
            {
                "@type": "DefinedTerm",
                "name": "Section 52 CGST Act (TCS)",
                "description": "TCS at 0.50 percent (0.25 percent CGST plus 0.25 percent SGST or UTGST, or 0.50 percent IGST) on the net value of taxable supplies through the platform; effective from 10 July 2024 (reduced from earlier 1 percent); reported in Form GSTR-8."
            },
            {
                "@type": "DefinedTerm",
                "name": "Section 9(5) CGST Act",
                "description": "Notified services where the ECO is deemed the supplier and pays GST directly - cab aggregators (Uber, Ola), accommodation booking (Oyo, MakeMyTrip), housekeeping and restaurant services through food delivery platforms (Swiggy, Zomato)."
            },
            {
                "@type": "DefinedTerm",
                "name": "Form GST REG-07",
                "description": "Application for GST registration as a tax collector at source - ECO registration form under Rule 12 CGST Rules; per Rule 12(1A), ECO without physical presence in a State or UT mentions that State in Part-A and the principal place of business in Part-B."
            },
            {
                "@type": "DefinedTerm",
                "name": "Form GSTR-8",
                "description": "Monthly TCS return by ECO declaring TCS collected from suppliers; due 10th of next month; suppliers can claim TCS credit in their GSTR-2X auto-population and offset against output GST."
            },
            {
                "@type": "DefinedTerm",
                "name": "Notification 34/2023-Central Tax",
                "description": "Dated 31 July 2023 - relaxation for goods suppliers through ECO; registration required only if aggregate turnover exceeds INR 40 lakh (INR 20 lakh for special category states); earlier mandatory regardless of turnover."
            },
            {
                "@type": "DefinedTerm",
                "name": "Consumer Protection (E-Commerce) Rules 2020",
                "description": "Notified by Ministry of Consumer Affairs on 23 July 2020 under Consumer Protection Act 2019; mandate grievance officer plus nodal officer for law enforcement, complete product listings, no fake reviews, transparent cancellation, return and refund policies."
            },
            {
                "@type": "DefinedTerm",
                "name": "FDI Press Note 2 of 2018",
                "description": "DPIIT notification dated 26 December 2018 - in e-commerce, FDI permitted only in the marketplace model; inventory ownership by FDI-backed e-commerce platform prohibited."
            },
            {
                "@type": "DefinedTerm",
                "name": "Section 122 CGST Penalty",
                "description": "For operating without GST registration where required - 100 percent of tax due OR INR 10,000 (whichever higher); Section 122(1B) specific to ECO TCS default (retrospective from 1 October 2023 once notified)."
            }
        ]
    }
    </script>
